def range_summary(nums):
    if not nums:
        return ''

    distinct = sorted(set(nums))
    ranges = []
    start = None
    for num in distinct:
        if start is None or num != start + 1:
            if start is not None:
                ranges.append(f'{start}-{start + len(range(start, num)) - 1}')
            start = num
    if start is not None:
        ranges.append(str(start))
    return ','.join(ranges)
